import React, { useState, useRef, useEffect } from "react";
import { createPortal } from "react-dom";
import QRCode from "qrcode";
import "font-awesome/css/font-awesome.min.css";

const Chatbot = () => {
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [message, setMessage] = useState("");
  const [messages, setMessages] = useState([
    {
      text: "Welcome to Rayu's portfolio! Ask me about services, pricing, React skills, contact info, projects, or timelines.",
      type: "bot"
    }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const [isMounted, setIsMounted] = useState(false);
  const avatarUrl = "https://cdn-icons-png.flaticon.com/512/4712/4712027.png";
  const messagesRef = useRef(null);

  useEffect(() => {
    setIsMounted(true);
    return () => setIsMounted(false);
  }, []);

  const toggleChat = () => {
    setIsChatOpen(!isChatOpen);
  };

  const sendMessage = async (e) => {
    e.preventDefault();
    const userMessage = message.trim();
    if (!userMessage) return;

    addMessage(userMessage, "user");

    if (userMessage.toLowerCase().includes("qr")) {
      const qrCode = await generateQRCode(userMessage);
      addMessage(qrCode, "bot", true);
    } else {
      const botReply = getBotReply(userMessage);
      setTimeout(() => {
        addMessage(botReply, "bot");
      }, 500);
    }

    setMessage("");
  };

  const addMessage = (textOrQrCode, type, isQrCode = false) => {
    const message = isQrCode
      ? { qrCode: textOrQrCode, type }
      : { text: textOrQrCode, type };
    setMessages((prevMessages) => [...prevMessages, message]);
  };

  const generateQRCode = async (text) => {
    try {
      return await QRCode.toDataURL(text);
    } catch (err) {
      console.error("QR Code generation failed:", err);
      return null;
    }
  };

  const getBotReply = (userMessage) => {
    const lowerMessage = userMessage.toLowerCase();

    if (lowerMessage.includes("hello") || lowerMessage.includes("hi")) {
      return "Hi there! Keen to chat about Rayu's work?";
    } else if (lowerMessage.includes("price") || lowerMessage.includes("cost")) {
      return "Pricing: Landing pages $200-500, business sites $500-1500, e-commerce $1000-3000. Hourly rate $25-50.";
    } else if (lowerMessage.includes("contact") || lowerMessage.includes("reach")) {
      return "Contact: Telegram @President_Alein, email choengrayu307@gmail.com, phone +855 96 998 3479.";
    } else if (lowerMessage.includes("skills") || lowerMessage.includes("tech")) {
      return "Skills: React, JavaScript, Node.js, Java, C++, HTML/CSS, MongoDB, MySQL, Flutter.";
    } else if (lowerMessage.includes("project") || lowerMessage.includes("portfolio")) {
      return "Projects include: 3D Portfolio, E-commerce Platform, Task Management App, Weather Dashboard.";
    } else {
      return "I'm ready to help - ask about services, pricing, skills, timelines, or contact info!";
    }
  };

  if (!isMounted) return null;

  return createPortal(
    <div className="chatbot">
      <div className="bot-icon" onClick={toggleChat}>
        <div className="icon-inner">
          <i className="fa fa-commenting"></i>
        </div>
      </div>
      {isChatOpen && (
        <div className="chat-window">
          <div className="chat-header">
            <h4>Rayu's Assistant</h4>
            <span className="close-icon" onClick={toggleChat}>
              <i className="fa fa-times"></i>
            </span>
          </div>
          <div className="chat-content">
            <div className="messages" ref={messagesRef}>
              {messages.map((msg, index) => (
                <div key={index} className={`message ${msg.type}`}>
                  {msg.type === "bot" && (
                    <img className="avatar" src={avatarUrl} alt="Bot" />
                  )}
                  <div className="message-text">
                    {msg.qrCode ? (
                      <img src={msg.qrCode} alt="QR" />
                    ) : (
                      <div>{msg.text}</div>
                    )}
                  </div>
                </div>
              ))}
            </div>
            <form onSubmit={sendMessage} className="chat-input">
              <input
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                type="text"
                placeholder="Send a message..."
              />
              <button type="submit">
                <i className="fa fa-paper-plane"></i>
              </button>
            </form>
          </div>
        </div>
      )}
    </div>,
    document.body
  );
};

export default Chatbot;
